import { useEffect, useState, type ReactNode } from 'react';

import { fetchMe, type MeResponse } from '../api/me';
import type { AsyncState } from '../hooks/useAsyncData';
import { MeContext } from './meContext';
import { useCurrentUser } from './useCurrentUser';

/**
 * Fetches `/me` once the user is authenticated and shares it via `MeContext`.
 *
 * The fetch is gated on `useCurrentUser()` (not done on bare mount) so that in
 * real-auth mode we wait until MSAL has an account — otherwise the request would
 * race ahead of the bearer token and 401. In dev-bypass the user is present
 * immediately. Re-runs if the signed-in identity changes.
 */
export function MeProvider({ children }: { children: ReactNode }) {
  const user = useCurrentUser();
  const [state, setState] = useState<AsyncState<MeResponse>>({ status: 'loading' });

  // Reset to loading the instant the signed-in identity changes — including
  // sign-out (user→null) — so the previous user's /me (and its
  // is_workspace_admin) can never linger and keep admin UI visible. Render-phase
  // adjustment, not an effect (an effect can't setState synchronously, and the
  // reset must land before children read the context this render).
  const userId = user?.homeAccountId ?? null;
  const [seenUserId, setSeenUserId] = useState(userId);
  if (userId !== seenUserId) {
    setSeenUserId(userId);
    setState({ status: 'loading' });
  }

  useEffect(() => {
    if (!user) return;
    let cancelled = false;
    fetchMe()
      .then((data) => {
        if (!cancelled) setState({ status: 'ok', data });
      })
      .catch((err: unknown) => {
        if (!cancelled) {
          setState({ status: 'error', error: err instanceof Error ? err.message : String(err) });
        }
      });
    return () => {
      cancelled = true;
    };
    // `user` is memoized by CurrentUserProvider (stable unless the signed-in
    // identity actually changes), so this refetches on real identity change only.
  }, [user]);

  return <MeContext.Provider value={state}>{children}</MeContext.Provider>;
}

import { Component, type ErrorInfo, type ReactNode } from 'react';

import { ErrorState } from './feedback/ErrorState';

interface Props {
  children: ReactNode;
}

interface State {
  error: Error | null;
}

/**
 * Catches render-time errors anywhere in the app subtree and shows an antd
 * fallback instead of React's blank screen. (main.tsx's bootstrap `.catch`
 * only covers the pre-render MSAL bootstrap; this covers everything after the
 * first paint.) Error boundaries must be class components — there is no hook
 * equivalent for `getDerivedStateFromError`.
 */
export class ErrorBoundary extends Component<Props, State> {
  state: State = { error: null };

  static getDerivedStateFromError(error: Error): State {
    return { error };
  }

  componentDidCatch(error: Error, info: ErrorInfo): void {
    // Surfaced to the console (and, once wired, App Insights) — fail loud.
    console.error('Unhandled render error', error, info.componentStack);
  }

  render(): ReactNode {
    if (this.state.error) {
      // A render-time crash is a client-side 500-equivalent — use the shared
      // in-brand error page (its 5xx branch offers Reload).
      return <ErrorState code={500} message={this.state.error.message} />;
    }
    return this.props.children;
  }
}

import { DeleteOutlined } from '@ant-design/icons';
import { App, Alert, Button, Drawer, Empty, Flex, Select, Spin, Tag, Tooltip } from 'antd';
import SimpleList from '../SimpleList';
import { useEffect, useRef, useState } from 'react';

import {
  grantShare,
  listShares,
  revokeShare,
  type Share,
  type SharePermission,
  searchUsers,
  updateShare,
  type UserSummary,
} from '../../api/shares';
import { useCurrentUser } from '../../auth/useCurrentUser';
import { useAsyncData } from '../../hooks/useAsyncData';

/** The grantable levels, in ladder order, with human labels. `admin` is the
 *  workspace-admin (implicit on every suite, never granted) and `owner` is the
 *  creator — neither is grantable (ADR 0027 / #482). */
const PERMISSION_OPTIONS: { value: SharePermission; label: string }[] = [
  { value: 'view', label: 'Can view' },
  { value: 'edit', label: 'Can edit' },
];

/**
 * Manage who can access a suite and at what level. Anyone with `view` can see
 * the collaborator list; only `owner`/`admin` (`canManage`) gets the add/change/
 * remove controls — matching the backend gate, which 403s an under-privileged
 * mutation regardless. Mounted only while open (`destroyOnHidden`), so the share
 * list refetches each time it's opened.
 */
export function SharePanel({
  open,
  suiteId,
  ownerId,
  canManage,
  onClose,
}: {
  open: boolean;
  suiteId: string;
  /** The suite's `created_by` — the owner can't be added as a share. */
  ownerId: string;
  canManage: boolean;
  onClose: () => void;
}) {
  return (
    // `destroyOnHidden` unmounts the body on close, so it (and its share-list
    // fetch) starts fresh on each open — matching the other drawers in the app.
    <Drawer title="Share suite" open={open} onClose={onClose} size={480} destroyOnHidden>
      <SharePanelBody suiteId={suiteId} ownerId={ownerId} canManage={canManage} />
    </Drawer>
  );
}

function SharePanelBody({
  suiteId,
  ownerId,
  canManage,
}: {
  suiteId: string;
  ownerId: string;
  canManage: boolean;
}) {
  const { state, reload } = useAsyncData(() => listShares(suiteId));
  // Best-effort UX lock on the signed-in user's own row (MSAL UPN ≈ their share
  // `email`): a non-owner admin self-revoking/-downgrading would brick the panel
  // (every later mutation 403s). The durable guard is server-side
  // (share_service._reject_self_target) since UPN can differ from mail and the
  // API is reachable directly; this just hides the footgun in the common case. #240.
  const currentEmail = useCurrentUser()?.username;

  if (state.status === 'loading') {
    return <Spin description="Loading collaborators…" />;
  }
  if (state.status === 'error') {
    return (
      <Alert type="error" showIcon title="Failed to load collaborators" description={state.error} />
    );
  }
  const shares = state.data;

  return (
    <Flex vertical gap={16}>
      {canManage && (
        <AddCollaborator
          suiteId={suiteId}
          excludedIds={[ownerId, ...shares.map((s) => s.user_id)]}
          onAdded={reload}
        />
      )}
      {shares.length === 0 ? (
        <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description="Not shared with anyone yet." />
      ) : (
        <SimpleList
          dataSource={shares}
          renderItem={(share) => (
            <ShareRow
              key={share.user_id}
              suiteId={suiteId}
              share={share}
              canManage={canManage}
              isSelf={!!currentEmail && share.email.toLowerCase() === currentEmail.toLowerCase()}
              onChanged={reload}
            />
          )}
        />
      )}
    </Flex>
  );
}

function ShareRow({
  suiteId,
  share,
  canManage,
  isSelf,
  onChanged,
}: {
  suiteId: string;
  share: Share;
  canManage: boolean;
  /** This row is the signed-in user — lock it so they can't remove their own access. */
  isSelf: boolean;
  onChanged: () => void;
}) {
  const { message } = App.useApp();
  const [busy, setBusy] = useState(false);

  const onPermissionChange = async (permission: SharePermission) => {
    setBusy(true);
    try {
      await updateShare(suiteId, share.user_id, permission);
      message.success(`${share.email}: ${permission}`);
      onChanged();
    } catch (err) {
      message.error(`Update failed: ${err instanceof Error ? err.message : 'unknown error'}`);
    } finally {
      setBusy(false);
    }
  };

  const onRevoke = async () => {
    setBusy(true);
    try {
      await revokeShare(suiteId, share.user_id);
      message.success(`${share.email}: removed`);
      onChanged();
    } catch (err) {
      message.error(`Remove failed: ${err instanceof Error ? err.message : 'unknown error'}`);
    } finally {
      setBusy(false);
    }
  };

  return (
    <SimpleList.Item
      actions={
        !canManage
          ? // Read-only for anyone without manage rights — including their own row.
            [<Tag key="perm">{share.permission}</Tag>]
          : isSelf
            ? [
                // A manager's own row is locked: self-revoke/-downgrade would 403
                // every later mutation and brick the panel (backend rejects it too,
                // share_service._reject_self_target). #240.
                <Tooltip key="perm" title="You can’t change your own access">
                  <Tag>{share.permission} · You</Tag>
                </Tooltip>,
              ]
            : [
                <Select
                  key="perm"
                  size="small"
                  value={share.permission}
                  options={PERMISSION_OPTIONS}
                  disabled={busy}
                  onChange={onPermissionChange}
                  style={{ width: 110 }}
                />,
                <Button
                  key="remove"
                  size="small"
                  type="text"
                  danger
                  icon={<DeleteOutlined />}
                  loading={busy}
                  onClick={onRevoke}
                  aria-label={`Remove ${share.email}`}
                />,
              ]
      }
    >
      <SimpleList.Item.Meta
        title={share.display_name ?? share.email}
        description={share.display_name ? share.email : undefined}
      />
    </SimpleList.Item>
  );
}

function AddCollaborator({
  suiteId,
  excludedIds,
  onAdded,
}: {
  suiteId: string;
  /** Owner + already-shared users — hidden from the picker (backend rejects them too). */
  excludedIds: string[];
  onAdded: () => void;
}) {
  const { message } = App.useApp();
  const [options, setOptions] = useState<UserSummary[]>([]);
  const [searching, setSearching] = useState(false);
  const [userId, setUserId] = useState<string>();
  const [permission, setPermission] = useState<SharePermission>('view');
  const [adding, setAdding] = useState(false);
  const timer = useRef<ReturnType<typeof setTimeout>>(undefined);
  // Monotonic token so a slow earlier search can't overwrite a newer one's
  // results (last-wins); unmount bumps it to a sentinel to drop any in-flight
  // response, and clears the pending debounce so it never fires post-unmount.
  const latest = useRef(0);
  useEffect(
    () => () => {
      clearTimeout(timer.current);
      latest.current = -1;
    },
    [],
  );

  // Debounce the directory query so a fast typist fires one search, not one per
  // keystroke. The 2-char floor mirrors the backend (a shorter query returns []).
  const onSearch = (raw: string) => {
    const q = raw.trim();
    clearTimeout(timer.current);
    if (q.length < 2) {
      setOptions([]);
      setSearching(false); // a pending debounce was cancelled — drop its spinner
      return;
    }
    setSearching(true);
    const token = (latest.current += 1);
    timer.current = setTimeout(() => {
      searchUsers(q)
        .then((users) => {
          if (token !== latest.current) return; // superseded by a newer search
          setOptions(users.filter((u) => !excludedIds.includes(u.id)));
        })
        .catch(() => {
          if (token === latest.current) setOptions([]);
        })
        .finally(() => {
          if (token === latest.current) setSearching(false);
        });
    }, 300);
  };

  const onAdd = async () => {
    if (!userId) return;
    setAdding(true);
    try {
      const share = await grantShare(suiteId, { user_id: userId, permission });
      message.success(`${share.email}: shared`);
      setUserId(undefined);
      setOptions([]);
      setPermission('view');
      onAdded();
    } catch (err) {
      message.error(`Share failed: ${err instanceof Error ? err.message : 'unknown error'}`);
    } finally {
      setAdding(false);
    }
  };

  return (
    <Flex gap={8} align="center">
      <Select
        showSearch
        value={userId}
        placeholder="Search by email or name"
        filterOption={false}
        onSearch={onSearch}
        onChange={setUserId}
        notFoundContent={searching ? <Spin size="small" /> : null}
        options={options.map((u) => ({
          value: u.id,
          label: u.display_name ? `${u.display_name} · ${u.email}` : u.email,
        }))}
        style={{ flex: 1 }}
      />
      <Select
        value={permission}
        options={PERMISSION_OPTIONS}
        onChange={setPermission}
        style={{ width: 110 }}
      />
      <Button type="primary" loading={adding} disabled={!userId} onClick={onAdd}>
        Add
      </Button>
    </Flex>
  );
}

